import java.util.*;

public class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        int n = nums.length;
        long[] answer = new long[queries.length];

        // Precompute the popcount-depth for each number in nums
        long[] popcountDepth = new long[n];
        for (int i = 0; i < n; i++) {
            popcountDepth[i] = computePopcountDepth(nums[i]);
        }

        // For efficient range queries, we use a segment tree
        SegmentTree segmentTree = new SegmentTree(n, popcountDepth);

        for (int i = 0; i < queries.length; i++) {
            if (queries[i][0] == 1) {
                // Query type 1: count numbers in [l, r] with popcount-depth equal to k
                int l = (int) queries[i][1];
                int r = (int) queries[i][2];
                int k = (int) queries[i][3];
                answer[i] = segmentTree.queryRange(l, r, k);
            } else {
                // Query type 2: update a value in nums
                int idx = (int) queries[i][1];
                long val = queries[i][2];
                nums[idx] = val;
                long oldDepth = popcountDepth[idx];
                long newDepth = computePopcountDepth(val);
                popcountDepth[idx] = newDepth;
                segmentTree.update(idx, newDepth);
            }
        }

        return answer;
    }

    // Compute the popcount-depth of a number
    private static long computePopcountDepth(long x) {
        long depth = 0;
        while (x > 0) {
            x = popcount(x);
            depth++;
        }
        return depth;
    }

    // Compute the number of 1s in the binary representation of a number
    private static long popcount(long x) {
        long count = 0;
        while (x > 0) {
            x &= x - 1;
            count++;
        }
        return count;
    }

    // Segment Tree implementation for range queries and point updates
    static class SegmentTree {
        int n;
        int size;
        long[] tree;

        SegmentTree(int n, long[] data) {
            this.n = n;
            this.size = 1;
            while (this.size < n) {
                this.size <<= 1;
            }
            this.tree = new long[2 * this.size];
            // Initialize leaves
            for (int i = 0; i < n; i++) {
                this.tree[this.size + i] = data[i];
            }
            // Build the tree
            for (int i = this.size - 1; i > 0; i--) {
                this.tree[i] = this.tree[2 * i] + this.tree[2 * i + 1];
            }
        }

        // Update a value at a position
        void update(int pos, long value) {
            pos += this.size;
            this.tree[pos] = value;
            pos >>= 1;
            while (pos >= 1) {
                this.tree[pos] = this.tree[2 * pos] + this.tree[2 * pos + 1];
                pos >>= 1;
            }
        }

        // Query the sum of values in a range [l, r]
        long queryRange(int l, int r, int k) {
            long res = 0;
            l += this.size;
            r += this.size;
            while (l <= r) {
                if (l % 2 == 1) {
                    res += this.tree[l];
                    l++;
                }
                if (r % 2 == 0) {
                    res += this.tree[r];
                    r--;
                }
                l >>= 1;
                r >>= 1;
            }
            return res;
        }
    }
}
