import { createHash } from 'crypto';

function solve(nums, queries) {
    const n = nums.length;
    const answer = [];

    // Precompute the popcount-depth for each number in nums
    const popcountDepth = new Array(n);
    for (let i = 0; i < n; i++) {
        popcountDepth[i] = computePopcountDepth(nums[i]);
    }

    // For efficient range queries, we use a segment tree
    const segmentTree = new SegmentTree(n, popcountDepth);

    for (const query of queries) {
        if (query[0] === 1) {
            // Query type 1: count numbers in [l, r] with popcount-depth equal to k
            const l = query[1];
            const r = query[2];
            const k = query[3];
            const count = segmentTree.queryRange(l, r, k);
            answer.push(count);
        } else {
            // Query type 2: update a value in nums
            const idx = query[1];
            const val = query[2];
            nums[idx] = val;
            const oldDepth = popcountDepth[idx];
            const newDepth = computePopcountDepth(val);
            popcountDepth[idx] = newDepth;
            segmentTree.update(idx, newDepth);
        }
    }

    return answer;
}

// Compute the popcount-depth of a number
function computePopcountDepth(x) {
    let depth = 0;
    while (x > 0) {
        x = popcount(x);
        depth++;
    }
    return depth;
}

// Compute the number of 1s in the binary representation of a number
function popcount(x) {
    let count = 0;
    while (x) {
        x &= x - 1;
        count++;
    }
    return count;
}

// Segment Tree implementation for range queries and point updates
class SegmentTree {
    constructor(n, data) {
        this.n = n;
        this.size = 1;
        while (this.size < n) {
            this.size <<= 1;
        }
        this.tree = new Array(2 * this.size);
        // Initialize leaves
        for (let i = 0; i < n; i++) {
            this.tree[this.size + i] = data[i];
        }
        // Build the tree
        for (let i = this.size - 1; i > 0; i--) {
            this.tree[i] = this.tree[2 * i] + this.tree[2 * i + 1];
        }
    }

    // Update a value at a position
    update(pos, value) {
        pos += this.size;
        this.tree[pos] = value;
        pos >>= 1;
        while (pos >= 1) {
            this.tree[pos] = this.tree[2 * pos] + this.tree[2 * pos + 1];
            pos >>= 1;
        }
    }

    // Query the sum of values in a range [l, r]
    queryRange(l, r, k) {
        let res = 0;
        l += this.size;
        r += this.size;
        while (l <= r) {
            if (l % 2 === 1) {
                res += this.tree[l];
                l++;
            }
            if (r % 2 === 0) {
                res += this.tree[r];
                r--;
            }
            l >>= 1;
            r >>= 1;
        }
        return res;
    }
}
